#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define MAXLEN 46
#define HASH_SIZE 131071

typedef struct Node{char key[MAXLEN];struct Node*next;}Node;

unsigned int hash(const char*s){unsigned int h=5381;while(*s){h=((h<<5)+h)+(unsigned char)(*s);s++;}return h%HASH_SIZE;}
int exists(Node**table,const char*s){unsigned int idx=hash(s);Node*cur=table[idx];while(cur){if(strcmp(cur->key,s)==0)return 1;cur=cur->next;}return 0;}
void insert(Node**table,const char*s){unsigned int idx=hash(s);Node*node=(Node*)malloc(sizeof(Node));strcpy(node->key,s);node->next=table[idx];table[idx]=node;}
void clearTable(Node**table){for(int i=0;i<HASH_SIZE;++i){Node*cur=table[i];while(cur){Node*tmp=cur;cur=cur->next;free(tmp);}table[i]=NULL;}}
int main(){int T;if(scanf("%d",&T)!=1)return 0;while(T--){int N;scanf("%d",&N);char*arr=(char*)malloc(N*MAXLEN);for(int i=0;i<N;++i)scanf("%s",arr+i*MAXLEN);Node*table[HASH_SIZE]={0};char*result=(char*)malloc(2*N+1);int pos=0;for(int i=N-1;i>=0;--i){char*s=arr+i*MAXLEN;if(!exists(table,s)){insert(table,s);int len=strlen(s);result[pos++]=s[len-2];result[pos++]=s[len-1];}}result[pos]='\0';printf("%s\n",result);clearTable(table);free(arr);free(result);}return 0;}

