const fs=require('fs');
const lines=fs.readFileSync(0,'utf-8').trim().split('\n');
let idx=0;
const T=parseInt(lines[idx++],10);
let output=[];
for(let t=0;t<T;t++){
  const N=parseInt(lines[idx++],10);
  const names=[];
  for(let i=0;i<N;i++) names.push(lines[idx++].trim());
  const seen=new Set();
  let res='';
  for(let i=N-1;i>=0;i--){
    const name=names[i];
    if(!seen.has(name)){
      seen.add(name);
      res+=name.slice(-2);
    }
  }
  output.push(res);
}
console.log(output.join('\n'));
